float beatFade(float beat, float peakBeat)
{
    float t = mod(beat - peakBeat + 4.0, 4.0);

    float fadeOut = clamp(1.0 - t, 0.0, 1.0);
    float fadeIn  = clamp(t - 3.0, 0.0, 1.0);

    return max(fadeOut, fadeIn);
}

float periodicBeatFade(float beatCount, float peakPeriod)
{
    float phase = mod(beatCount, peakPeriod);

    float fadeIn  = clamp(phase - (peakPeriod - 1.0), 0.0, 1.0);
    float fadeOut = clamp(1.0 - phase, 0.0, 1.0);

    return max(fadeIn, fadeOut);
}
